import React, { useEffect, useMemo, useRef, useState } from 'react';
import { PUZZLES, getPuzzleByLabel } from './data/puzzles.js';
import {
  areAdjacent,
  canonicalBridgeKey,
  canAddBridge,
  computeCurrentCounts,
  isVictory,
  parseBridgeKey
} from './utils/hashiLogic.js';

const UNIT = 40;
const W = 800;
const H = 600;

function px(n) {
  return n * UNIT;
}

function bridgeLinesPixels(from, to, count) {
  const x1 = px(from.x);
  const y1 = px(from.y);
  const x2 = px(to.x);
  const y2 = px(to.y);

  if (count === 1) return [{ x1, y1, x2, y2 }];
  // double: 2 parallel lines offset 4px perpendicular
  const offset = 4;
  if (from.x === to.x) {
    return [
      { x1: x1 - offset, y1, x2: x2 - offset, y2 },
      { x1: x1 + offset, y1, x2: x2 + offset, y2 }
    ];
  }
  return [
    { x1, y1: y1 - offset, x2, y2: y2 - offset },
    { x1, y1: y1 + offset, x2, y2: y2 + offset }
  ];
}

function getNeighbors(islands, from, dir) {
  // return nearest island in direction if aligned
  let best = null;
  for (const isl of islands) {
    if (isl.id === from.id) continue;
    if (dir === 'left' && isl.y === from.y && isl.x < from.x) {
      if (!best || isl.x > best.x) best = isl;
    }
    if (dir === 'right' && isl.y === from.y && isl.x > from.x) {
      if (!best || isl.x < best.x) best = isl;
    }
    if (dir === 'up' && isl.x === from.x && isl.y < from.y) {
      if (!best || isl.y > best.y) best = isl;
    }
    if (dir === 'down' && isl.x === from.x && isl.y > from.y) {
      if (!best || isl.y < best.y) best = isl;
    }
  }
  return best;
}

export default function App() {
  const [puzzleLabel, setPuzzleLabel] = useState(PUZZLES[0].label);
  const puzzle = useMemo(() => getPuzzleByLabel(puzzleLabel), [puzzleLabel]);

  const [bridges, setBridges] = useState(() => new Map());
  const [selectedId, setSelectedId] = useState(null);
  const [cursorId, setCursorId] = useState(puzzle.islands[0]?.id || null);
  const [error, setError] = useState(null);

  const counts = useMemo(() => computeCurrentCounts(puzzle.islands, bridges), [puzzle.islands, bridges]);
  const victory = useMemo(() => isVictory(puzzle.islands, bridges), [puzzle.islands, bridges]);

  const islandsById = useMemo(() => {
    const m = new Map();
    for (const isl of puzzle.islands) m.set(isl.id, isl);
    return m;
  }, [puzzle.islands]);

  const svgRef = useRef(null);

  useEffect(() => {
    // On puzzle change: fully reset bridges & selection/cursor
    setBridges(new Map());
    setSelectedId(null);
    setCursorId(puzzle.islands[0]?.id || null);
    setError(null);
  }, [puzzleLabel]);

  function applyDelta(from, to, delta) {
    const res = canAddBridge(puzzle.islands, bridges, from, to, delta);
    if (!res.valid) {
      setError(res.error);
      return;
    }
    setError(null);

    const key = canonicalBridgeKey(from, to);
    const cur = bridges.get(key) || 0;
    const next = cur + delta;
    const nb = new Map(bridges);
    if (next <= 0) nb.delete(key);
    else nb.set(key, next);
    setBridges(nb);
  }

  function cycleBridge(from, to) {
    if (!areAdjacent(puzzle.islands, from, to)) {
      setError('Cannot connect non-adjacent islands');
      return;
    }
    const key = canonicalBridgeKey(from, to);
    const cur = bridges.get(key) || 0;
    const next = (cur + 1) % 3; // 0->1->2->0

    const delta = next - cur;
    if (delta === 0) {
      setError(null);
      return;
    }

    // apply in steps so validation uses correct delta (could be -2 when cycling 2->0)
    if (delta === -2) {
      applyDelta(from, to, -1);
      applyDelta(from, to, -1);
    } else if (delta === 2) {
      applyDelta(from, to, 1);
      applyDelta(from, to, 1);
    } else {
      applyDelta(from, to, delta);
    }
  }

  function onIslandClick(id) {
    const isl = islandsById.get(id);
    if (!isl) return;

    if (!selectedId) {
      setSelectedId(id);
      setCursorId(id);
      return;
    }
    if (selectedId === id) {
      // reselect; no toggle
      setSelectedId(id);
      return;
    }
    const from = islandsById.get(selectedId);
    const to = isl;
    cycleBridge(from, to);
    setSelectedId(null);
  }

  function onBridgeToggle(key) {
    const { x1, y1, x2, y2 } = parseBridgeKey(key);
    const from = puzzle.islands.find((i) => i.x === x1 && i.y === y1);
    const to = puzzle.islands.find((i) => i.x === x2 && i.y === y2);
    if (!from || !to) return;
    cycleBridge(from, to);
  }

  function resetPuzzle() {
    setBridges(new Map());
    setSelectedId(null);
    setError(null);
  }

  useEffect(() => {
    function onKeyDown(e) {
      if (!puzzle.islands.length) return;

      const cur = islandsById.get(cursorId) || puzzle.islands[0];

      if (e.key === 'Escape') {
        setSelectedId(null);
        return;
      }

      const dirMap = {
        ArrowLeft: 'left',
        ArrowRight: 'right',
        ArrowUp: 'up',
        ArrowDown: 'down'
      };

      if (e.key in dirMap) {
        e.preventDefault();
        const next = getNeighbors(puzzle.islands, cur, dirMap[e.key]);
        if (next) setCursorId(next.id);
        return;
      }

      if (e.key === 'Enter') {
        e.preventDefault();
        if (!selectedId) {
          setSelectedId(cur.id);
        } else {
          const from = islandsById.get(selectedId);
          const to = cur;
          if (from && to && from.id !== to.id) {
            cycleBridge(from, to);
          }
          setSelectedId(null);
        }
      }
    }

    window.addEventListener('keydown', onKeyDown);
    return () => window.removeEventListener('keydown', onKeyDown);
  }, [cursorId, islandsById, puzzle.islands, selectedId, bridges]);

  const bridgeEntries = useMemo(() => {
    const arr = [...bridges.entries()].filter(([, n]) => n > 0);
    arr.sort((a, b) => a[0].localeCompare(b[0]));
    return arr;
  }, [bridges]);

  return (
    <>
      <div className="controls">
        <label>
          Puzzle:{' '}
          <select
            value={puzzleLabel}
            onChange={(e) => setPuzzleLabel(e.target.value)}
          >
            {PUZZLES.map((p) => (
              <option key={p.label} value={p.label}>
                {p.label}
              </option>
            ))}
          </select>
        </label>
        <button onClick={resetPuzzle}>Reset</button>

        {error ? <div className="error-message">{error}</div> : null}
        {victory ? <div className="victory-banner">SOLVED!</div> : null}
      </div>

      <svg
        ref={svgRef}
        className="board"
        width={W}
        height={H}
        viewBox={`0 0 ${W} ${H}`}
      >
        {/* Bridges */}
        <g stroke="#00ff66" strokeWidth="3" strokeLinecap="round">
          {bridgeEntries.map(([key, n]) => {
            const { x1, y1, x2, y2 } = parseBridgeKey(key);
            const a = puzzle.islands.find((i) => i.x === x1 && i.y === y1);
            const b = puzzle.islands.find((i) => i.x === x2 && i.y === y2);
            if (!a || !b) return null;
            const lines = bridgeLinesPixels(a, b, n);

            return (
              <g
                key={key}
                onContextMenu={(e) => {
                  e.preventDefault();
                  onBridgeToggle(key);
                }}
                onClick={(e) => {
                  if (e.ctrlKey) onBridgeToggle(key);
                }}
                style={{ cursor: 'pointer' }}
              >
                {lines.map((ln, idx) => (
                  <line
                    key={idx}
                    x1={ln.x1}
                    y1={ln.y1}
                    x2={ln.x2}
                    y2={ln.y2}
                  />
                ))}
                {/* Hit area */}
                <line
                  x1={px(a.x)}
                  y1={px(a.y)}
                  x2={px(b.x)}
                  y2={px(b.y)}
                  stroke="transparent"
                  strokeWidth="14"
                />
              </g>
            );
          })}
        </g>

        {/* Cursor (not a circle) */}
        {cursorId ? (() => {
          const c = islandsById.get(cursorId);
          if (!c) return null;
          const size = 26;
          return (
            <rect
              x={px(c.x) - size / 2}
              y={px(c.y) - size / 2}
              width={size}
              height={size}
              fill="none"
              stroke={selectedId ? '#ffcc00' : '#00ff66'}
              strokeWidth="2"
            />
          );
        })() : null}

        {/* Islands */}
        <g>
          {puzzle.islands.map((isl) => {
            const isSelected = selectedId === isl.id;
            const curCount = counts.get(isl.id) || 0;
            const satisfied = curCount === isl.value;

            return (
              <g
                key={isl.id}
                transform={`translate(${px(isl.x)}, ${px(isl.y)})`}
                onClick={() => onIslandClick(isl.id)}
                style={{ cursor: 'pointer' }}
              >
                <circle
                  r={14}
                  fill="#000"
                  stroke={isSelected ? '#ffcc00' : satisfied ? '#00ff66' : '#00aa44'}
                  strokeWidth={2}
                />
                <text
                  x={0}
                  y={5}
                  textAnchor="middle"
                  fontSize="14"
                  fill="#00ff66"
                >
                  {isl.value}
                </text>
              </g>
            );
          })}
        </g>
      </svg>
    </>
  );
}
