const ERR_NON_ADJ = 'Cannot connect non-adjacent islands';
const ERR_MAX2 = 'Max 2 bridges per pair';
const ERR_EXCEED = 'Island would exceed its number';
const ERR_CROSS = 'Bridges would cross';

export function canonicalBridgeKey(from, to) {
  const a = { x: from.x, y: from.y };
  const b = { x: to.x, y: to.y };
  const first = a.x < b.x || (a.x === b.x && a.y <= b.y) ? a : b;
  const second = first === a ? b : a;
  return `${first.x},${first.y},${second.x},${second.y}`;
}

export function parseBridgeKey(key) {
  const [x1, y1, x2, y2] = key.split(',').map(Number);
  return { x1, y1, x2, y2 };
}

export function isAxisAligned(a, b) {
  return a.x === b.x || a.y === b.y;
}

export function islandsByCoord(islands) {
  const m = new Map();
  for (const isl of islands) m.set(`${isl.x},${isl.y}`, isl);
  return m;
}

export function areAdjacent(islands, from, to) {
  if (!isAxisAligned(from, to)) return false;
  if (from.x === to.x) {
    const x = from.x;
    const yMin = Math.min(from.y, to.y);
    const yMax = Math.max(from.y, to.y);
    for (const isl of islands) {
      if (isl.x === x && isl.y > yMin && isl.y < yMax) return false;
    }
    return true;
  }
  const y = from.y;
  const xMin = Math.min(from.x, to.x);
  const xMax = Math.max(from.x, to.x);
  for (const isl of islands) {
    if (isl.y === y && isl.x > xMin && isl.x < xMax) return false;
  }
  return true;
}

function segmentForBridge(key) {
  const { x1, y1, x2, y2 } = parseBridgeKey(key);
  if (x1 === x2) {
    return { orient: 'V', x: x1, y1: Math.min(y1, y2), y2: Math.max(y1, y2) };
  }
  return { orient: 'H', y: y1, x1: Math.min(x1, x2), x2: Math.max(x1, x2) };
}

export function bridgesWouldCross(bridges) {
  const keys = [...bridges.entries()].filter(([, n]) => n > 0).map(([k]) => k);
  for (let i = 0; i < keys.length; i++) {
    const a = segmentForBridge(keys[i]);
    for (let j = i + 1; j < keys.length; j++) {
      const b = segmentForBridge(keys[j]);
      if (a.orient === b.orient) continue;
      const h = a.orient === 'H' ? a : b;
      const v = a.orient === 'V' ? a : b;
      // Proper crossing only at interior (not at endpoints)
      const crosses = v.x > h.x1 && v.x < h.x2 && h.y > v.y1 && h.y < v.y2;
      if (crosses) return true;
    }
  }
  return false;
}

export function computeCurrentCounts(islands, bridges) {
  const counts = new Map(islands.map((i) => [i.id, 0]));
  const byCoord = islandsByCoord(islands);

  for (const [key, n] of bridges.entries()) {
    if (!n) continue;
    const { x1, y1, x2, y2 } = parseBridgeKey(key);
    const a = byCoord.get(`${x1},${y1}`);
    const b = byCoord.get(`${x2},${y2}`);
    if (!a || !b) continue;
    counts.set(a.id, (counts.get(a.id) || 0) + n);
    counts.set(b.id, (counts.get(b.id) || 0) + n);
  }
  return counts;
}

export function canAddBridge(islands, bridges, from, to, delta) {
  if (!from || !to || from.id === to.id) return { valid: false, error: ERR_NON_ADJ };
  if (!areAdjacent(islands, from, to)) return { valid: false, error: ERR_NON_ADJ };

  const key = canonicalBridgeKey(from, to);
  const cur = bridges.get(key) || 0;
  const next = cur + delta;

  if (next < 0) return { valid: true, error: null };
  if (next > 2) return { valid: false, error: ERR_MAX2 };

  // capacity check per-island
  const counts = computeCurrentCounts(islands, bridges);
  const fromCount = counts.get(from.id) || 0;
  const toCount = counts.get(to.id) || 0;

  if (fromCount + delta > from.value || toCount + delta > to.value) {
    return { valid: false, error: ERR_EXCEED };
  }

  // crossing check: simulate
  const test = new Map(bridges);
  if (next === 0) test.delete(key);
  else test.set(key, next);

  if (bridgesWouldCross(test)) return { valid: false, error: ERR_CROSS };

  return { valid: true, error: null };
}

export function checkConnectivity(islands, bridges) {
  if (islands.length <= 1) return true;
  const byCoord = islandsByCoord(islands);
  const adj = new Map(islands.map((i) => [i.id, new Set()]));

  for (const [key, n] of bridges.entries()) {
    if (!n) continue;
    const { x1, y1, x2, y2 } = parseBridgeKey(key);
    const a = byCoord.get(`${x1},${y1}`);
    const b = byCoord.get(`${x2},${y2}`);
    if (!a || !b) continue;
    adj.get(a.id).add(b.id);
    adj.get(b.id).add(a.id);
  }

  const start = islands[0].id;
  const q = [start];
  const seen = new Set([start]);
  while (q.length) {
    const id = q.shift();
    for (const nb of adj.get(id) || []) {
      if (!seen.has(nb)) {
        seen.add(nb);
        q.push(nb);
      }
    }
  }
  return seen.size === islands.length;
}

export function isVictory(islands, bridges) {
  if (bridgesWouldCross(bridges)) return false;
  const counts = computeCurrentCounts(islands, bridges);
  for (const isl of islands) {
    if ((counts.get(isl.id) || 0) !== isl.value) return false;
  }
  return checkConnectivity(islands, bridges);
}

export const ERROR_TEXTS = {
  ERR_NON_ADJ,
  ERR_MAX2,
  ERR_EXCEED,
  ERR_CROSS
};
EOF
