      </div>

      <svg
        ref={svgRef}
        className="board"
        width={W}
        height={H}
        viewBox={`0 0 ${W} ${H}`}
      >
        {/* Bridges */}
        <g stroke="#00ff66" strokeWidth="3" strokeLinecap="round">
          {bridgeEntries.map(([key, n]) => {
            const { x1, y1, x2, y2 } = parseBridgeKey(key);
            const a = puzzle.islands.find((i) => i.x === x1 && i.y === y1);
            const b = puzzle.islands.find((i) => i.x === x2 && i.y === y2);
            if (!a || !b) return null;
            const lines = bridgeLinesPixels(a, b, n);

            return (
              <g
                key={key}
                onContextMenu={(e) => {
                  e.preventDefault();
                  onBridgeToggle(key);
                }}
                onClick={(e) => {
                  if (e.ctrlKey) onBridgeToggle(key);
