                style={{ cursor: 'pointer' }}
              >
                {lines.map((ln, idx) => (
                  <line
                    key={idx}
                    x1={ln.x1}
                    y1={ln.y1}
                    x2={ln.x2}
                    y2={ln.y2}
                  />
                ))}
                {/* Hit area */}
                <line
                  x1={px(a.x)}
                  y1={px(a.y)}
                  x2={px(b.x)}
                  y2={px(b.y)}
                  stroke="transparent"
                  strokeWidth="14"
                />
              </g>
