        {/* Cursor (not a circle) */}
        {cursorId ? (() => {
          const c = islandsById.get(cursorId);
          if (!c) return null;
          const size = 26;
          return (
            <rect
              x={px(c.x) - size / 2}
              y={px(c.y) - size / 2}
              width={size}
              height={size}
              fill="none"
              stroke={selectedId ? '#ffcc00' : '#00ff66'}
              strokeWidth="2"
            />
          );
        })() : null}

        {/* Islands */}
        <g>
          {puzzle.islands.map((isl) => {
            const isSelected = selectedId === isl.id;
            const curCount = counts.get(isl.id) || 0;
            const satisfied = curCount === isl.value;

            return (
              <g
                key={isl.id}
                transform={`translate(${px(isl.x)}, ${px(isl.y)})`}
                onClick={() => onIslandClick(isl.id)}
                style={{ cursor: 'pointer' }}
              >
                <circle
                  r={14}
                  fill="#000"
                  stroke={isSelected ? '#ffcc00' : satisfied ? '#00ff66' : '#00aa44'}
                  strokeWidth={2}
                />
                <text
                  x={0}
                  y={5}
                  textAnchor="middle"
                  fontSize="14"
                  fill="#00ff66"
                >
                  {isl.value}
                </text>
              </g>
            );
          })}
        </g>
      </svg>
    </>
  );
